class Solution:
    def calculate(self, s: str) -> int:
        s = s.replace(" ","")
        print(s, len(s))

        stack = []
        curr_stack = []
        par_depth = 0

        cur_num = ""
        start_digit=True

        for i in range(len(s)):
            if (s[i]=="-" or s[i]=="+"):
                if len(cur_num)==0:
                    print("s")
                    cur_num+=s[i]
                else:
                    print("a", cur_num)
                    curr_stack.append(cur_num)
                    cur_num=""
                    cur_num+=s[i]
            
            if s[i].isdigit():
                cur_num+=s[i]

            if s[i]=="(":
                if len(cur_num)!=0:
                    print("a2", cur_num)
                    curr_stack.append(cur_num)
                    cur_num=""
                print("a3")
                stack.append(curr_stack)
                curr_stack = []

            if s[i]==")":
                if len(cur_num)!=0:
                    print("a4", cur_num)
                    curr_stack.append(cur_num)
                    cur_num=""
                summ = 0
                for n in curr_stack:
                    summ+=int(n)
                # print("summ", summ)
                if s[i]==")":
                    curr_stack=stack.pop()
                    print("1",curr_stack)
                    if len(curr_stack)!=0:
                        if curr_stack[-1]=="-":
                            summ = -summ
                        curr_stack[-1]=str(summ)
                    else:
                        curr_stack.append(str(summ))
                    print(curr_stack)
                # if len(s) == i+1:
                #     return summ
            if len(s) == i+1:
                if len(cur_num)!=0:
                    print("a5", cur_num)
                    curr_stack.append(cur_num)
                summ = 0
                for n in curr_stack:
                    summ+=int(n)
                return summ





